RewardConfig = {}
RewardConfig.Rewards = {}

function RewardConfig:loadConfig()
    local configs = FileUtil.getConfigFromCsv("setting/RewardConfig.csv", 3)
    for _, config in pairs(configs) do
        local reward = {
            id = tonumber(config.Id),
            icon = config.Image,
            rewardId = config.RewardId,
            count = tonumber(config.Count),
            name = config.Name
        }
        self.Rewards[reward.id] = reward
    end
end

function RewardConfig:getRewardById(id)
    return self.Rewards[tonumber(id)]
end